INSERT INTO permissions (code, description, version, created_at, updated_at) VALUES ('OOS_INVESTIGATE', 'Manage OOS investigations and sub-entities', 0, now(), now()), ('OOS_RETEST_APPROVE', 'Order and record retest/resample results', 0, now(), now()), ('OOS_DISPOSE', 'Perform QA disposition decisions on OOS cases', 0, now(), now()), ('OOS_REOPEN', 'Reopen closed OOS cases', 0, now(), now()) ON CONFLICT (code) DO NOTHING;
INSERT INTO role_permissions (role_id, permission_id, version, created_at, updated_at) SELECT r.id, p.id, 0, now(), now() FROM roles r JOIN permissions p ON p.code IN ('OOS_INVESTIGATE','OOS_RETEST_APPROVE','OOS_DISPOSE','OOS_REOPEN') WHERE r.name IN ('ADMIN','QA_MANAGER') ON CONFLICT DO NOTHING;
INSERT INTO role_permissions (role_id, permission_id, version, created_at, updated_at) SELECT r.id, p.id, 0, now(), now() FROM roles r JOIN permissions p ON p.code IN ('OOS_INVESTIGATE','OOS_RETEST_APPROVE') WHERE r.name = 'AUTHOR' ON CONFLICT DO NOTHING;
